customElements.define("user-card", class extends HTMLElement {
  connectedCallback() {
    this.render();
  }
});

async function loadProfile(account) {
  const response = await fetch(`/api/profile?account=${account}`);
  if (!response.ok) throw new Error("request failed");
  return response.json();
}

export async function loadConfig(root: string) {
  const file = await findConfigFile(root);
  if (!file) return null;
  return await bundleAndLoadConfigFile(file);
}

server.watcher.on("change", async (file) => {
  const modules = moduleGraph.getModulesByFile(file);
  await handleHmrUpdate(file, modules);
});

export const load = async ({ fetch }) => {
  const response = await fetch("/api/posts");
  return { posts: await response.json() };
};
